init_eqs:
i=0; loop (5000,i[0]=0; gmem[i]=0; i+=1;);
octaves=3; minbpm=75; maxbpm=200; nres_oct=60;
nres_extra=nres_oct/log(2)*log(maxbpm/minbpm/2);
nres=nres_oct*octaves+nres_extra;
bstep = log(2)/nres_oct;
nres_out = ceil(nres_oct+nres_extra); //int is necessary !

maxind = 40;
i=0;
loop (nres,
//precalculate BPM
(8*i)[3]=minbpm*exp(i*bstep);
//precalculate weighting
if (i<=nres_out,(8*i)[4]=min(2,1+sin($pi*i/nres_out)*3)/2,0);;
i+=1);

ripple_form = 5 + int(rand(20))

frame_eqs:
//Martin/Nitorami - DFT based BPM identification
//If you need a good BPM detection, why don't you simply use my code ? - Nitorami
//Credits in comp shader code. Don't blame me.

dt=1/fps;
tcorr = (dt - dt_); //to compensate timing errors caused by MD's time smoothing
dt_= dt;
treal += dt + tcorr*38; //I-share of timing error comp.
exc=2*bass+mid+treb;  //choose what you like but mind this could affect quali
d0= exp(-1.5*dt);
i=0; avg = 0;
loop (nres,
n = 8*i;
w = 2*$pi/60*n[3];
d = 1-dt*w*0.013; //DFT smoothing optimised for nres_oct=60
arg = treal*w + tcorr*15000; //P-share of timing error comp.
n[1] = n[1]*d +exc*cos(arg)*(1-d); //DFT real part
n[2] = n[2]*d +exc*sin(arg)*(1-d); //DFT imaginary part
if (i<nres_out,
n2 = 8*(i+nres_oct);
n4 = 8*(i+nres_oct*2);
sum = sqrt (sqr(n[1])+sqr(n[2]) + sqr(n2[1])+sqr(n2[2]) + sqr(n4[1])+sqr(n4[2]));
avg += sum;
n[0]= n[0]*d0+sum*(1-d0)*n[4];
if (n[0]>(8*promax)[0], promax=max(2,min(nres_out-2,i));,0);
,0);
i += 1;);
avg_ = avg_*d0 + (1-d0)*avg/nres_out;

//Resist frequent BPM changes
m8 = 8*maxind;
wait += abs(m8[0]-(8*promax)[0])*dt*100;
if (wait>abs(promax-maxind)*80/nres_oct, maxind=promax; wait = 0,0);

//OUTPUT
BPM = m8[3];

//Se7enSlasher - Convert BPM to integer and do a simple rounding.
//intBPM = floor(BPM+.5); //More efficient way?
intBPM = int(BPM);

//Se7enSlasher - Timed Stop Technique

//Se7enSlasher - Change the intBPM value to 0 when there is no sound.
timeUntilStop = if (bass+mid+treb > 0, 2, timeUntilStop);
timeUntilStop -= 1/fps;
intBPM = if(timeUntilStop <= 0, 0, intBPM);

linear_trans = if(!intBPM, linear_trans -= (1/fps)*3, linear_trans += (1/fps)*3);

//Prevent from getting to gap (0 - 1).
linear_trans = if(linear_trans < 0, 0, linear_trans);
linear_trans = if(linear_trans > 1, 1, linear_trans);

log_trans = log(linear_trans * 50 + 1) / 3.95;

q7 = log_trans;

//END

q1 = intBPM;

time_imgsync += (1/fps) * (q1/30);
time_imgsync = if (time_imgsync >= 4, 0, time_imgsync);
q2 = pow(10, ((bass_att+mid_att+treb)/3.25)-3);
q3 = int(time_imgsync);

q4 = 1/aspectx;
q5 = 1/aspecty+.75;

BPMTime = (sin(time * $PI / (60 / q1)) + 1) / 2;
q6 = BPMTime;
time_delay = if(time_delay >= .35 && bass > 2, 0, time_delay += 1/fps);
ripple_form = if(time_delay == 0, 5 + int(rand(20)), ripple_form);
q8 = ripple_form;
monitor = intBPM;
